import json
d=json.load(open('.leandag/dag.json'))
nodes={n['id']:n for n in d['nodes']}
adj={nid:set() for nid in nodes}
for e in d['edges']:
    if e['from'] in adj and e['to'] in adj:
        adj[e['from']].add(e['to']); adj[e['to']].add(e['from'])
seen=set();comps=[]
for nid in nodes:
    if nid in seen: continue
    st=[nid];comp=[];seen.add(nid)
    while st:
        x=st.pop();comp.append(x)
        for y in adj[x]:
            if y not in seen: seen.add(y);st.append(y)
    comps.append(comp)
comps.sort(key=len,reverse=True)
print('num components:', len(comps))
print('sizes:', [len(c) for c in comps])
co={x:i for i,c in enumerate(comps) for x in c}
print('Jacobian comp:', co['def:Jacobian'], 'size', len(comps[co['def:Jacobian']]))
# Goal directed ancestor cone size
import collections
# edge from->to means to uses from; ancestors of goal = nodes reachable going from->? 
# ancestor of goal: all g such that there's directed path g -> ... -> goal. Build reverse adjacency on 'uses': node uses dep => dep is ancestor. edge from=dep,to=consumer. ancestors(goal) = nodes that can reach goal following from->to.
fwd=collections.defaultdict(set)  # from->to
for e in d['edges']:
    fwd[e['from']].add(e['to'])
# reachability to goal: reverse BFS from goal over fwd reversed
rev=collections.defaultdict(set)
for a,bs in fwd.items():
    for b in bs: rev[b].add(a)
seen2={'def:Jacobian'}; st=['def:Jacobian']
while st:
    x=st.pop()
    for y in rev[x]:
        if y not in seen2: seen2.add(y); st.append(y)
print('goal directed ancestor cone size (incl goal):', len(seen2), 'of', len(nodes))
# print residual detached clusters
for i,c in enumerate(comps[1:],1):
    print(f'  residual cluster {i}: size {len(c)} :: {sorted(c)[:6]}')
